INSERT INTO changelog (version, title_en, title_fr, body_en, body_fr, created_at) VALUES
  ('1.73', 'Feed management, changelog UI, UX polish', 'Gestion des flux, journal des mises à jour, polish UX', 'changelog table + GET /api/changelog + Changelog page. Feed management: GET /api/feeds-admin, score/delete actions, toasts. Layout 872px; EN/FR below icons; feed ranking title tooltip; fetch-feeds sets fetched_at.', 'Table changelog + page journal. Gestion des flux : feeds-admin, scoring 30j, toasts. Largeur 872px ; EN/FR sous icônes ; survol source stats ; fetched_at sur fetch-feeds.', '2026-04-07T12:00:00Z'),
  ('1.72', 'Stats redesign & fetch delay fix', 'Refonte stats & correction délai fetch', 'Stats 3-state flow, kpi_only, article ranking lazy 50. Cron Monitor avg delay: scored_at − fetched_at as Xm XXs; fetched_at on inserts.', 'Stats 3 états, kpi_only, classement articles par 50. Délai moyen Cron : scored_at − fetched_at en Xm XXs ; fetched_at à l’insertion.', '2026-04-06T12:00:00Z'),
  ('1.71', 'Cron optimization phase 2', 'Optimisation cron phase 2', 'cron-fetch ~10 min cycle, adaptive mini-score, 6s reserve. cron-score multi-topic 12s deadline, threshold 20. fetchAndStoreTopicDynamic returns inserted count.', 'cron-fetch cycle ~10 min, mini-score adaptatif. cron-score multi-topic deadline 12s, seuil 20. Retour {summary, inserted} après fetch.', '2026-04-05T12:00:00Z'),
  ('1.70', 'Avg delay fix & doc sync', 'Correction délai moyen & sync doc', 'Cron Monitor avg delay cohort: pub_date 24h + scored only. SPEC sync.', 'Cohorte délai moyen : pub_date 24h + scorés. Sync SPEC.', '2026-04-04T12:00:00Z'),
  ('1.69', 'Cron optimization phase 1', 'Optimisation cron phase 1', 'Minute batched fetch k=min(ceil(N/15),3), ~12s deadline. cron-score backlog priority, post-fetch mini-score ≤15.', 'Fetch minute k=min(ceil(N/15),3), deadline ~12s. cron-score priorité backlog, mini-score post-fetch ≤15.', '2026-04-03T12:00:00Z'),
  ('1.68', 'Supabase pagination fix & Top 20 refresh', 'Pagination Supabase & refresh Top 20', '/api/cron-stats 1000-row pagination. Top 20 auto-refresh 5 min. Topic badge on Top 20.', '/api/cron-stats pagination 1000 lignes. Top 20 refresh 5 min. Badge topic.', '2026-04-02T12:00:00Z'),
  ('1.67', 'Summary metadata line (mobile)', 'Ligne méta résumé (mobile)', 'Compact summary stats line; mobile typography ≤640px.', 'Ligne compacte articles/scorés/analysés IA ; typo mobile ≤640px.', '2026-04-01T12:00:00Z'),
  ('1.66', 'Version bump & SPEC tree', 'Bump version & arbre SPEC', 'SPEC project tree folder name 8news/.', 'Arborescence SPEC corrigée (8news/).', '2026-03-31T12:00:00Z'),
  ('1.65', 'Copy link, Cron Reason, NEW badge', 'Copie lien, raison Cron, badge NEW', 'Copy-to-clipboard on cards; Cron statusReason column; NEW badge <1h on Top 20.', 'Copie lien ; colonne raison Cron ; badge NEW <1h sur Top 20.', '2026-03-30T12:00:00Z'),
  ('1.64', 'Topic clears Top 20', 'Topic vide le Top 20', 'Selecting topic clears Top 20; prompt to pick period.', 'Choix topic masque Top 20 ; invite à choisir une période.', '2026-03-29T12:00:00Z'),
  ('1.63', 'Home icon & Summary title', 'Icône accueil & titre résumé', 'Home + logo reset Top 20; topic name in Summary title; removed standalone Top 20 button.', 'Accueil + logo réinitialisent Top 20 ; nom du topic dans le titre résumé ; bouton Top 20 retiré.', '2026-03-28T12:00:00Z'),
  ('1.62', 'Score ≥ 7 label, Top 20 default, scroll top', 'Libellé Score ≥ 7, Top 20 par défaut', 'Rename Hit % to Score ≥ 7; feeds (7d); Top 24h default feed; scroll-to-top button.', 'Hit % → Score ≥ 7 ; flux (7j) ; Top 20 par défaut 24h ; bouton retour haut.', '2026-03-27T12:00:00Z'),
  ('1.61', 'Cron Monitor & All Articles', 'Cron Monitor & onglet Tous les articles', 'Cron Monitor page; All Articles by score; maxArticles up to 100; lazy All tab; article stats in Summary; local TZ timeline.', 'Page Cron Monitor ; onglet Tous trié par score ; maxArticles 100 ; lazy load ; stats dans résumé ; fuseau local timeline.', '2026-03-26T12:00:00Z'),
  ('1.60', 'Cron scoring batch & timeout', 'Batch scoring cron & timeout', '50 articles/batch, backlog skip, OpenAI timeout handling.', 'Lots de 50 articles, skip backlog, timeout OpenAI.', '2026-03-25T12:00:00Z'),
  ('1.59', 'Discover feeds for existing topics', 'Découverte de flux pour topics existants', 'Discover feeds by AI in topic edit view.', 'Bouton découverte de flux IA dans l’édition topic.', '2026-03-24T12:00:00Z'),
  ('1.58', 'Topics loading & reorder', 'Chargement topics & réordonnancement', 'Spinner while topics load; active/inactive toggle; drag & drop reorder.', 'Spinner topics ; actif/inactif ; glisser-déposer ordre.', '2026-03-23T12:00:00Z'),
  ('1.57', 'Stats periods & banner', 'Périodes stats & bannière', 'Update banner top-right; stats 1h/3h/6h/today; logo → home.', 'Bannière mise à jour en haut à droite ; stats 1h/3h/6h/aujourd’hui ; logo → accueil.', '2026-03-22T12:00:00Z'),
  ('1.56', 'Cron round-robin fix', 'Correction round-robin cron', 'Timestamps before processing; ≤100 score/run; score every minute.', 'Horodatage avant traitement ; ≤100 score/run ; score chaque minute.', '2026-03-21T12:00:00Z'),
  ('1.55', 'AI scoring tiers & feed discovery', 'Tiers scoring IA & découverte flux', 'Generate scoring with AI; auto RSS discovery on topic create; refresh topics on home return.', 'Génération critères IA ; découverte RSS à la création ; refresh topics au retour accueil.', '2026-03-20T12:00:00Z'),
  ('1.54', 'Compact KPIs & Anthropic topic', 'KPI compacts & topic Anthropic', '7 KPIs one line; Anthropic topic + 20 feeds.', '7 KPIs une ligne ; topic Anthropic + 20 flux.', '2026-03-19T12:00:00Z'),
  ('1.53', 'Prompts in DB, hardcoded cleanup', 'Prompts en base, nettoyage dur', 'Dynamic prompts from DB; removed prompts.ts, rss-feeds.ts, scoring-prompts.ts.', 'Prompts dynamiques Supabase ; suppression données en dur.', '2026-03-18T12:00:00Z'),
  ('1.52', 'Dynamic topics & crons', 'Topics dynamiques & crons', 'Topics/feeds from DB; TopicsPage; round-robin crons; removed 18 hardcoded crons.', 'Topics/flux en base ; TopicsPage ; crons round-robin ; suppression 18 crons figés.', '2026-03-17T12:00:00Z'),
  ('1.51', 'Scoring throughput & KPI filter', 'Débit scoring & filtre KPI', 'Boost scoring throughput; fix KPI period filter.', 'Montée en débit scoring ; correctif filtre période KPI.', '2026-03-16T12:00:00Z'),
  ('1.50', 'Update banner & stats periods', 'Bannière maj & périodes stats', 'Replace auto-reload with banner; stats yesterday, 3d, 7d, 30d.', 'Bannière au lieu du reload auto ; stats hier, 3j, 7j, 30j.', '2026-03-15T12:00:00Z'),
  ('1.49', 'Full Stats dashboard', 'Tableau de bord Stats complet', 'KPIs, score distribution, feed ranking, top articles, topic comparison.', 'KPIs, distribution scores, classement flux, top articles, comparaison topics.', '2026-03-14T12:00:00Z'),
